import React, { createContext, useReducer, useContext, ReactNode } from 'react';

interface Job {
  id: string;
  title: string;
  description: string;
  requirements: string;
  salaryRange: string;
  location: string;
  companyLogo: string;
}

interface JobState {
  jobs: Job[];
  savedJobs: Job[];
}

interface JobAction {
  type: 'SET_JOBS' | 'SAVE_JOB';
  payload: any;
}

const initialState: JobState = {
  jobs: [],
  savedJobs: [],
};

const JobContext = createContext<{ state: JobState; dispatch: React.Dispatch<JobAction> } | undefined>(undefined);

const jobReducer = (state: JobState, action: JobAction): JobState => {
  switch (action.type) {
    case 'SET_JOBS':
      return { ...state, jobs: action.payload };
    case 'SAVE_JOB':
      return { ...state, savedJobs: [...state.savedJobs, action.payload] };
    default:
      return state;
  }
};

export const JobProvider = ({ children }: { children: ReactNode }) => {
  const [state, dispatch] = useReducer(jobReducer, initialState);

  return (
    <JobContext.Provider value={{ state, dispatch }}>
      {children}
    </JobContext.Provider>
  );
};

export const useJob = () => {
  const context = useContext(JobContext);
  if (!context) {
    throw new Error('useJob must be used within a JobProvider');
  }
  return context;
};

